/* ================= helpers ================= */
const $=s=>document.querySelector(s), $$=s=>[...document.querySelectorAll(s)];
const uid=()=>Math.random().toString(36).slice(2,9);
const esc=s=>String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
const CREST='data:image/png;base64,', LOCKUP='data:image/png;base64,';
const todayISO=()=>new Date().toISOString().slice(0,10);
const fmtDate=iso=>{if(!iso)return'';const[y,m,d]=iso.split('-');return`${d}.${m}.${y.slice(2)}`};

/* tag factory */
const T=(c,r)=>({c,r:!!r});
const item=(name,desc,price,tags,note)=>({id:uid(),name,desc:desc||'',price:price||'',tags:tags||[],note:note||'',hidden:false});
const rule=()=>({id:uid(),rule:true});

const sec=(name,items,opt)=>Object.assign({id:uid(),name,prices:true,note:'',items},opt||{});
function normaliseSectionColumns(s){
 const cols=Math.max(1,Math.min(4,Number(s.cols)||1));s.cols=cols;s.descMode=s.descMode==='below'?'below':'inline';
 if(cols===1){delete s.columnNames;(s.items||[]).forEach(it=>delete it.col);return s}
 s.columnNames=Array.from({length:cols},(_,i)=>(s.columnNames&&s.columnNames[i])||`Column ${i+1}`);
 const items=s.items||[];
 let needsSpread=items.some(it=>it.col==null||it.col<0||it.col>=cols);
 if(needsSpread){
   const dishes=items.filter(it=>!it.rule), per=Math.ceil(Math.max(1,dishes.length)/cols);let di=0;
   items.forEach(it=>{if(it.rule){it.col=Math.min(cols-1,Math.floor(di/Math.max(1,per)))}else{it.col=Math.min(cols-1,Math.floor(di/Math.max(1,per)));di++}})
 }
 items.forEach(it=>it.col=Math.max(0,Math.min(cols-1,Number(it.col)||0)));
 return s
}
function ensureRootRules(m){
 m.rootRules=m.rootRules||[];
 // Migrate any legacy lines out of sections. A line belongs to the menu root,
 // positioned after the section it previously appeared in.
 (m.sections||[]).forEach(s=>{
  const legacy=(s.items||[]).filter(it=>it.rule);
  if(legacy.length){
   legacy.forEach(it=>{delete it.col;m.rootRules.push({id:it.id||uid(),rule:true,afterSectionId:s.id,position:'between'})});
   s.items=(s.items||[]).filter(it=>!it.rule);
  }
 });
 return m
}
function normaliseMenuColumns(m){ensureRootRules(m);(m.sections||[]).forEach(normaliseSectionColumns);return m}


