/* ================= state ================= */
const LSKEY='griffinMenuStudio.v1';
let state, undoStack=[];
function load(){try{const raw=localStorage.getItem(LSKEY);if(raw){state=JSON.parse(raw);return}}catch(e){}state=seedState()}
function persist(){try{localStorage.setItem(LSKEY,JSON.stringify(state))}catch(e){}}
function snapshot(){undoStack.push(JSON.stringify(state));if(undoStack.length>60)undoStack.shift()}
function undo(){if(!undoStack.length)return;state=JSON.parse(undoStack.pop());persist();renderAll()}
function commit(o){ // o: {ed:bool} whether editor needs re-render
 persist();renderPreview();renderRail();if(o&&o.ed)renderEditor();
}
const cur=()=>state.menus.find(m=>m.id===state.cur)||state.menus[0];
const findItem=(m,iid)=>{for(const s of m.sections){const it=s.items.find(i=>i.id===iid);if(it)return{s,it}}return null};

/* ================= menu page rendering ================= */
function tagsStr(tags){
 if(!tags||!tags.length)return'';
 const order=state.settings.dietKey.map(k=>k.c);
 const st=[...tags].sort((a,b)=>(a.r-b.r)||(order.indexOf(a.c)-order.indexOf(b.c)));
 return '('+st.map(t=>t.r?t.c+' on request':t.c).join(', ')+')';
}
function usedCodes(m){const set=new Set();m.sections.forEach(s=>s.items.forEach(i=>{if(!i.hidden)(i.tags||[]).forEach(t=>set.add(t.c))}));return state.settings.dietKey.filter(k=>set.has(k.c))}
function menuHTML(m,opts){
 opts=opts||{};
 ensureRootRules(m);
 const mv=!!opts.move; // move-mode wraps blocks as movable
 const pos=m.pos||{};
 const off=key=>{const p=pos[key];return p&&(p.x||p.y)?`transform:translate(${p.x}px,${p.y}px);`:''};
 // wrap a block so it can be dragged (only in edit preview)
 const B=(key,inner,extra)=>{
   if(!opts.edit)return `<div class="mblk" style="${off(key)}${extra||''}">${inner}</div>`;
   return `<div class="mblk movable" data-move="${key}" style="${off(key)}${extra||''}"><span class="moveHint">drag</span>${inner}</div>`;
 };
 const E=(path,txt,cls)=>opts.edit
   ?`<span class="${cls||''}" data-edit="${path}" contenteditable="plaintext-only" spellcheck="false">${esc(txt)}</span>`
   :`<span class="${cls||''}">${esc(txt)}</span>`;
 const st=m.style||{};
 const itemHTML=(it,s)=>{
   const tg=tagsStr(it.tags);
   const below=s.descMode==='below'||(s.descMode==null&&st.stacked);
   if(below){
     let x=`<div class="m-item stacked"><span class="m-nm">${E('item:'+it.id+'.name',it.name)}${s.prices&&it.price?` <span class="m-pr">${E('item:'+it.id+'.price',it.price)}</span>`:''}</span>`;
     const bits=[];
     if(it.desc||opts.edit)bits.push(E('item:'+it.id+'.desc',it.desc||''));
     if(tg)bits.push(`<span class="m-tg">${esc(tg)}</span>`);
     if(it.note)bits.push(`<span class="m-nt">(${esc(it.note)})</span>`);
     if(bits.length)x+=`<span class="m-ds">${bits.join(' ')}</span>`;
     return x+'</div>';
   }
   let x=`<div class="m-item"><span class="m-nm">${E('item:'+it.id+'.name',it.name)}</span>`;
   if(it.desc||opts.edit)x+=` <span class="m-dash">-</span> <span class="m-ds">${E('item:'+it.id+'.desc',it.desc||'')}</span>`;
   if(tg)x+=` <span class="m-tg">${esc(tg)}</span>`;
   if(it.note)x+=` <span class="m-nt">(${esc(it.note)})</span>`;
   if(s.prices&&(it.price||opts.edit))x+=` <span class="m-pr">${E('item:'+it.id+'.price',it.price||'')}</span>`;
   return x+'</div>';
 };
 const ruleHTML=r=>`<div class="m-rule rule-${r.position||'between'}"></div>`;
 let h='';
 // header
 let head='';
 if(st.header==='crest')head+=`<img class="m-crest" src="${CREST}" alt="">`;
 if(st.header==='lockup')head+=`<img class="m-lockup" src="${LOCKUP}" alt="">`;
 if(st.header!=='lockup')head+=`<div class="m-title">${E('menu.name',m.name)}</div>`;
 else head+=`<div class="m-title" style="font-size:1.5em;margin-top:.2em">${E('menu.name',m.name)}</div>`;
 h+=B('header',head);
 if(m.headerNote||opts.edit)h+=B('hnote',`<div class="m-hnote">${E('menu.headerNote',m.headerNote||'')}</div>`);
 h+='<div class="body">';
 (m.rootRules||[]).filter(r=>r.position==='top').forEach(r=>{h+=B('rule:'+r.id,ruleHTML(r))});
 for(const s of m.sections){
  const list=opts.edit?s.items:s.items.filter(i=>!i.hidden);
  const dishes=list;
  if(!dishes.length&&!opts.edit)continue;
  let sec=`<div class="m-sech">${E('sec:'+s.id+'.name',s.name)}</div>`;
  if(s.note||opts.edit)sec+=`<div class="m-secnote">${E('sec:'+s.id+'.note',s.note||'')}</div>`;
  const rest=list;
  if(s.descMode==null)s.descMode=st.stacked?'below':'inline';
  normaliseSectionColumns(s);
  if(s.cols>1){
    const cols=Array.from({length:s.cols},()=>[]);
    rest.forEach(it=>cols[Math.max(0,Math.min(s.cols-1,Number(it.col)||0))].push(it));
    sec+=`<div class="m-items" style="--cols:${s.cols}">${cols.map((arr,ci)=>{
      let inner='';
      if((s.columnNames&&s.columnNames[ci])||opts.edit)inner+=`<div class="m-subh">${E('col:'+s.id+'.'+ci,(s.columnNames&&s.columnNames[ci])||'')}</div>`;
      for(const it of arr)inner+=itemHTML(it,s);
      return `<div class="m-col">${inner}</div>`
    }).join('')}</div>`;
  }else{
    sec+=`<div class="m-items">${rest.map(it=>itemHTML(it,s)).join('')}</div>`;
  }
  h+=B('sec:'+s.id,`<div class="m-sec ${s.cols>1?'multi':''}">${sec}</div>`);
  (m.rootRules||[]).filter(r=>r.afterSectionId===s.id&&r.position!=='top').forEach(r=>{h+=B('rule:'+r.id,ruleHTML(r))});
 }
 (m.rootRules||[]).filter(r=>!r.afterSectionId&&r.position!=='top').forEach(r=>{h+=B('rule:'+r.id,ruleHTML(r))});
 h+='</div>';
 let foot='';
 if(st.showKey){const u=usedCodes(m);if(u.length)foot+=B('key',`<div class="m-key">${esc(u.map(k=>`(${k.c}) ${k.l}`).join('  '))}</div>`)}
 foot+=B('footer',`<div class="m-foot">${E('menu.footer',m.footer||'')}</div>`);
 return `<div class="page ${st.paper==='A5'?'A5':''}" style="--sc:${st.sc||1};--dn:${st.dn||1}"><div class="inner">${h}<div class="print-footer-zone">${foot}</div></div></div>`;
}

/* ================= preview ================= */
let baseZoom=1, zoom=1, followFit=true;
function renderPreview(resetZoom){
 const m=cur();if(!m)return;
 if(resetZoom)followFit=true;
 const wrap=$('#pagewrap');
 wrap.innerHTML=menuHTML(m,{edit:true});
 $('#stPaper').textContent=(m.style.paper||'A4')+' \u00b7 BLUSH PREVIEW \u00b7 EXPORTS WHITE';
 document.documentElement.style.setProperty('--blush',state.settings.blush||'#F5E4DF');
 wrap.querySelectorAll('img').forEach(im=>{if(!im.complete)im.addEventListener('load',fitPage,{once:true})});
 fitPage();requestAnimationFrame(fitPage);setTimeout(fitPage,180);
 if(moveMode)$$('#pagewrap [data-edit]').forEach(el=>el.contentEditable='false');
 scheduleOverflowCheck();
 const shrunk=(m.style.sc&&m.style.sc<1)||(m.style.dn&&m.style.dn<1);
 $('#btnResetFit').style.display=shrunk?'inline-block':'none';
}
function overflowInfo(){
 const wrap=$('#pagewrap'),page=wrap.querySelector('.page'),inner=wrap.querySelector('.inner');
 if(!page||!inner)return{over:false,pages:1,used:0,limit:0};
 // The .page element can grow beyond its CSS min-height, so page.clientHeight is not a valid one-page limit.
 // Derive the physical paper height from its rendered width instead (A4 210x297, A5 148x210).
 const ratio=page.classList.contains('A5')?210/148:297/210;
 const limit=page.offsetWidth*ratio;
 const used=Math.max(inner.scrollHeight,inner.getBoundingClientRect().height);
 const pages=Math.max(1,Math.ceil((used-1)/limit));
 return{over:used>limit+2,pages,used,limit};
}
function checkOverflow(){
 const info=overflowInfo();
 $('#warnChip').classList.toggle('show',info.over);
 const wt=$('#warnText');if(wt)wt.textContent=info.over?`Needs about ${info.pages} pages`:`Fits on one page`;
 return info.over;
}
function scheduleOverflowCheck(){
 requestAnimationFrame(()=>requestAnimationFrame(checkOverflow));
 setTimeout(checkOverflow,120);setTimeout(checkOverflow,420);
}
function fitPage(){
 const wrap=$('#pagewrap'),page=wrap.querySelector('.page');if(!page)return;
 const sc=$('#stageScroll');
 const availW=sc.clientWidth-40;
 const pw=page.offsetWidth;
 if(pw<10||availW<10)return;
 baseZoom=Math.min(availW/pw,1.6);
 if(followFit)zoom=baseZoom;
 applyZoom();
}
function applyZoom(){
 const wrap=$('#pagewrap'),page=wrap.querySelector('.page');if(!page)return;
 const pw=page.offsetWidth,ph=page.offsetHeight;
 zoom=Math.max(0.2,Math.min(3,zoom));
 wrap.style.transform=`scale(${zoom})`;
 wrap.style.width=(pw*zoom)+'px';
 wrap.style.height=(ph*zoom)+'px';
 $('#scReset').textContent=Math.round(zoom*100)+'%';
}
function setZoom(z){followFit=false;zoom=z;applyZoom()}
$('#scUp').addEventListener('click',()=>setZoom(zoom*1.18));
$('#scDown').addEventListener('click',()=>setZoom(zoom/1.18));
$('#scReset').addEventListener('click',()=>{followFit=true;fitPage()});
window.addEventListener('resize',fitPage);
if(document.fonts&&document.fonts.ready)document.fonts.ready.then(()=>{fitPage();scheduleOverflowCheck()});

/* one-page auto-fit */
$('#btnAutoFit').addEventListener('click',()=>{
 const m=cur();snapshot();
 const s=m.style;s.dn=s.dn||1;s.sc=s.sc||1;
 const wrap=$('#pagewrap');
 let tries=0;
 while(tries<60){
  wrap.innerHTML=menuHTML(m,{edit:true});
  const page=wrap.querySelector('.page'),inner=wrap.querySelector('.inner');
  const ratio=page.classList.contains('A5')?210/148:297/210;const limit=page.offsetWidth*ratio;
  if(Math.max(inner.scrollHeight,inner.getBoundingClientRect().height)<=limit+2)break;
  if(s.dn>0.62)s.dn=+(s.dn-0.04).toFixed(2);
  else if(s.sc>0.74)s.sc=+(s.sc-0.02).toFixed(2);
  else break;
  tries++;
 }
 commit({ed:true});
 if(checkOverflow())alert('Still doesn\u2019t quite fit \u2014 try removing a dish, shortening a description, or splitting it across two menus.');
});
$('#btnResetFit').addEventListener('click',()=>{snapshot();const s=cur().style;s.sc=1;s.dn=1;commit({ed:true})});

/* inline editing on preview */
/* ================= arrange (free drag) mode ================= */
let moveMode=false, mdrag=null;
$('#btnMove').addEventListener('click',()=>{
 moveMode=!moveMode;
 document.body.classList.toggle('moveMode',moveMode);
 $('#btnMove').classList.toggle('act',moveMode);
 // in move mode, turn off contenteditable so drags don't start text editing
 $$('#pagewrap [data-edit]').forEach(el=>el.contentEditable=moveMode?'false':'plaintext-only');
});
$('#pagewrap').addEventListener('pointerdown',e=>{
 if(!moveMode)return;
 const blk=e.target.closest('.movable');if(!blk)return;
 e.preventDefault();
 const m=cur();const key=blk.dataset.move;
 m.pos=m.pos||{};const start=m.pos[key]||{x:0,y:0};
 mdrag={blk,key,sx:e.clientX,sy:e.clientY,ox:start.x||0,oy:start.y||0};
 blk.classList.add('moving');blk.setPointerCapture&&blk.setPointerCapture(e.pointerId);
 window.addEventListener('pointermove',onMoveDrag);
 window.addEventListener('pointerup',endMoveDrag,{once:true});
});
function onMoveDrag(e){
 if(!mdrag)return;
 const dx=(e.clientX-mdrag.sx)/zoom, dy=(e.clientY-mdrag.sy)/zoom;
 const nx=Math.round(mdrag.ox+dx), ny=Math.round(mdrag.oy+dy);
 mdrag.blk.style.transform=`translate(${nx}px,${ny}px)`;
 mdrag.nx=nx;mdrag.ny=ny;
}
function endMoveDrag(){
 if(!mdrag)return;
 window.removeEventListener('pointermove',onMoveDrag);
 mdrag.blk.classList.remove('moving');
 const m=cur();snapshot();
 m.pos=m.pos||{};
 if((mdrag.nx||0)===0&&(mdrag.ny||0)===0)delete m.pos[mdrag.key];
 else m.pos[mdrag.key]={x:mdrag.nx||mdrag.ox,y:mdrag.ny||mdrag.oy};
 mdrag=null;persist();
}
/* reset all positions helper (double-click a block to reset it) */
$('#pagewrap').addEventListener('dblclick',e=>{
 if(!moveMode)return;
 const blk=e.target.closest('.movable');if(!blk)return;
 const m=cur();if(m.pos&&m.pos[blk.dataset.move]){snapshot();delete m.pos[blk.dataset.move];commit()}
});

document.addEventListener('focusin',e=>{
 const el=e.target.closest('[data-edit]');if(!el)return;el.dataset.orig=el.textContent;
});
document.addEventListener('keydown',e=>{
 const el=e.target.closest&&e.target.closest('[data-edit]');
 if(el&&e.key==='Enter'&&el.dataset.edit!=='menu.footer'){e.preventDefault();el.blur()}
 if((e.ctrlKey||e.metaKey)&&e.key.toLowerCase()==='z'&&!e.target.closest('input,textarea,[contenteditable]')){e.preventDefault();undo()}
});
document.addEventListener('focusout',e=>{
 const el=e.target.closest&&e.target.closest('[data-edit]');if(!el)return;
 const val=el.textContent;
 if(val===el.dataset.orig)return;
 snapshot();
 applyEdit(el.dataset.edit,val);
 commit({ed:true});
});
function applyEdit(path,val){
 const m=cur();val=val.trim();
 if(path==='menu.name')m.name=val||m.name;
 else if(path==='menu.headerNote')m.headerNote=val;
 else if(path==='menu.footer')m.footer=val;
 else if(path.startsWith('sec:')){const[,rest]=path.split(':');const[id,f]=rest.split('.');const s=m.sections.find(x=>x.id===id);if(s)s[f]=val}
 else if(path.startsWith('item:')){const[,rest]=path.split(':');const[id,f]=rest.split('.');const r=findItem(m,id);if(r)r.it[f]=val}
 else if(path.startsWith('col:')){const parts=path.split(':');const s=m.sections.find(x=>x.id===parts[1]);if(s){normaliseSectionColumns(s);s.columnNames[Number(parts[2])]=val}}
}

/* ================= menu list (dropdown + mobile panel) ================= */
function renderRail(){
 const m=cur();
 const rows=state.menus.map(x=>`<button class="mrow ${x.id===state.cur?'on':''}" data-id="${x.id}"><span class="nm">${esc(x.name)}</span><span class="dt">${fmtDate(x.date)}</span></button>`).join('');
 $('#menusPanel').innerHTML=rows+`<button class="newrow" data-new>+ NEW MENU\u2026</button>`;
 $('#railScroll').innerHTML=rows;
}
function onMenuListClick(e){
 if(e.target.closest('[data-new]')){closePops();openGallery();return}
 const b=e.target.closest('.mrow');if(!b)return;
 state.cur=b.dataset.id;persist();closePops();renderAll(true);
 if(innerWidth<=940)setTab('edit');
}
$('#menusPanel').addEventListener('click',onMenuListClick);
$('#railScroll').addEventListener('click',onMenuListClick);
$('#btnNewMenuRail').addEventListener('click',openGallery);

/* rail show/hide + resize */
const mainGrid=$('#mainGrid');
function applyRailWidth(){mainGrid.style.setProperty('--railw',(state.settings.railWidth||230)+'px')}
function applyRailHidden(){mainGrid.classList.toggle('noRail',!!state.settings.railHidden);requestAnimationFrame(fitPage)}
$('#btnToggleRail').addEventListener('click',()=>{
 state.settings.railHidden=!state.settings.railHidden;persist();applyRailHidden();
});
(function railDrag(){
 const handle=$('#railHandle');let dragging=false;
 handle.addEventListener('pointerdown',e=>{
  dragging=true;handle.classList.add('drag');e.preventDefault();
  window.addEventListener('pointermove',move);window.addEventListener('pointerup',end,{once:true});
 });
 function move(e){
  if(!dragging)return;
  const rect=mainGrid.getBoundingClientRect();
  const w=Math.max(160,Math.min(420,e.clientX-rect.left));
  mainGrid.style.setProperty('--railw',w+'px');
 }
 function end(){
  dragging=false;handle.classList.remove('drag');window.removeEventListener('pointermove',move);
  const w=parseInt(getComputedStyle(mainGrid).getPropertyValue('--railw'))||230;
  state.settings.railWidth=w;persist();fitPage();
 }
})();
(function editorDrag(){
 const handle=$('#editorHandle');let dragging=false;
 handle.addEventListener('pointerdown',e=>{
  dragging=true;handle.classList.add('drag');e.preventDefault();
  window.addEventListener('pointermove',move);window.addEventListener('pointerup',end,{once:true});
 });
 function move(e){
  if(!dragging)return;
  const rect=mainGrid.getBoundingClientRect();
  const railOffset=state.settings.railHidden?0:((state.settings.railWidth||230)+6);
  const w=Math.max(300,Math.min(720,e.clientX-rect.left-railOffset));
  mainGrid.style.setProperty('--edw',w+'px');requestAnimationFrame(fitPage);
 }
 function end(){
  dragging=false;handle.classList.remove('drag');window.removeEventListener('pointermove',move);
  const w=parseInt(getComputedStyle(mainGrid).getPropertyValue('--edw'))||380;
  state.settings.editorWidth=w;persist();fitPage();
 }
})();
function applyEditorWidth(){mainGrid.style.setProperty('--edw',(state.settings.editorWidth||380)+'px')}
/* popovers */
function closePops(){$$('.more.open').forEach(x=>x.classList.remove('open'))}
$('#btnMore').addEventListener('click',e=>{e.stopPropagation();$('#more').classList.toggle('open')});
document.addEventListener('click',e=>{if(!e.target.closest('.more'))closePops()});
/* ================= editor ================= */
const ICONS={
 eye:'<svg viewBox="0 0 24 24"><path d="M2 12s3.5-7 10-7 10 7 10 7-3.5 7-10 7-10-7-10-7Z"/><circle cx="12" cy="12" r="3"/></svg>',
 eyeoff:'<svg viewBox="0 0 24 24"><path d="M3 3l18 18M10 5.3A9.8 9.8 0 0 1 12 5c6.5 0 10 7 10 7a17 17 0 0 1-3.2 4M6.4 6.5A16.5 16.5 0 0 0 2 12s3.5 7 10 7a9.9 9.9 0 0 0 4.4-1"/></svg>',
 x:'<svg viewBox="0 0 24 24"><path d="M6 6l12 12M18 6 6 18"/></svg>',
 up:'<svg viewBox="0 0 24 24"><path d="M6 15l6-6 6 6"/></svg>',
 dn:'<svg viewBox="0 0 24 24"><path d="M6 9l6 6 6-6"/></svg>',
 grip:'<svg viewBox="0 0 12 16"><g fill="currentColor" stroke="none"><circle cx="3" cy="3" r="1.4"/><circle cx="9" cy="3" r="1.4"/><circle cx="3" cy="8" r="1.4"/><circle cx="9" cy="8" r="1.4"/><circle cx="3" cy="13" r="1.4"/><circle cx="9" cy="13" r="1.4"/></g></svg>',
 tagOn:'<svg viewBox="0 0 24 24"><path d="M5 13l4 4L19 7"/></svg>'
};
function renderEditor(){
 const m=cur();if(!m)return;normaliseMenuColumns(m);
 $('#edName').value=m.name; $('#edDate').value=m.date||''; $('#edPaper').value=m.style.paper||'A4'; $('#edHeader').value=m.style.header||'title';
 const sc=$('#edScroll');
 const rootRuleRow=(r)=>`<div class="rootrule" data-rid="${r.id}"><span class="handle rulehandle" title="Drag line above, between or below sections">${ICONS.grip}</span><div class="rulebody"><span class="ruleline"></span><span class="rulelabel">menu line</span><span class="ruleline"></span></div><button class="iconb danger" data-act="delrootrule" title="Delete line">${ICONS.x}</button></div>`;
 const itemRow=(it)=>{
  return `<div class="item ${it.hidden?'hid':''}" data-iid="${it.id}">
    <span class="handle" title="Drag to move">${ICONS.grip}</span>
    <div class="ibody"><div class="irow1"><input class="iname" data-f="name" value="${esc(it.name)}" placeholder="Dish name"><input class="iprice" data-f="price" value="${esc(it.price)}" placeholder="£" inputmode="decimal"></div>
    <input class="idesc" data-f="desc" value="${esc(it.desc)}" placeholder="description - e.g. seeded chilli oil">
    <div class="irow3">${state.settings.dietKey.map(k=>{const t=(it.tags||[]).find(x=>x.c===k.c);const cls=t?(t.r?'tag req':'tag on'):'tag';return`<button class="${cls}" data-tag="${esc(k.c)}" title="${esc(k.l)} - click: on → on request → off">${esc(k.c)}${t&&t.r?' · req':''}</button>`}).join('')}<input class="inote" data-f="note" value="${esc(it.note||'')}" placeholder="note, e.g. £7 supplement"></div></div>
    <div class="itools"><button class="iconb" data-act="hide" title="${it.hidden?'Hidden from print - click to show':'Shown - click to hide from print'}">${it.hidden?ICONS.eyeoff:ICONS.eye}</button><button class="iconb danger" data-act="del" title="Delete dish">${ICONS.x}</button></div></div>`
 };
 let h=`<div class="rootdropzone edge" data-rootpos="top"></div>`;
 (m.rootRules||[]).filter(r=>r.position==='top').forEach(r=>{h+=rootRuleRow(r)});
 for(const s of m.sections){
  const cols=s.cols||1;
  h+=`<div class="sec" data-sid="${s.id}"><div class="sec-h"><input class="sname" value="${esc(s.name)}" data-f="name" title="Section name"><button class="iconb" data-act="secup" title="Move section up">${ICONS.up}</button><button class="iconb" data-act="secdn" title="Move section down">${ICONS.dn}</button><button class="pricetog ${s.prices?'on':''}" data-act="secprices" title="Show or hide prices">${s.prices?'£ prices on':'£ prices off'}</button><button class="descmode ${s.descMode==='below'?'on':''}" data-act="secdesc" title="Description layout for this section">${s.descMode==='below'?'desc below':'desc right'}</button><button class="pricetog colsbtn ${cols>1?'on':''}" data-act="seccols" title="Cycle from one to four columns">${cols} col${cols===1?'':'s'}</button><button class="iconb danger" data-act="secdel" title="Delete section">${ICONS.x}</button></div>
   <input class="sec-note-in" data-f="note" value="${esc(s.note||'')}" placeholder="Section note (optional) - e.g. All served with roast potatoes…">`;
  if(cols>1){
    h+=`<div class="sec-smartbar"><span><b>${cols} subsections</b> - rename them and drag dishes between them</span><span class="smart-note">Tip: empty columns stay valid</span></div><div class="colboard" style="--editor-cols:${cols}">`;
    for(let ci=0;ci<cols;ci++){
      const arr=s.items.filter(it=>(Number(it.col)||0)===ci);
      h+=`<div class="collane" data-sid="${s.id}" data-col="${ci}"><div class="colhead"><input class="colname" data-colname="${ci}" value="${esc(s.columnNames[ci]||'')}" placeholder="Subsection ${ci+1}"><span class="count">${arr.filter(x=>!x.rule).length}</span></div><div class="items" data-sid="${s.id}" data-col="${ci}">${arr.map(itemRow).join('')}${arr.length?'':'<div class="col-empty">Drop dishes here</div>'}</div><div class="col-addrow"><button data-act="add" data-col="${ci}">+ Dish</button></div></div>`;
    }
    h+=`</div><div class="addrow"><button data-act="copy">Copy a dish from another menu…</button></div>`;
  }else{
    h+=`<div class="quickhint"><b>Fast edit:</b> drag dishes by the dots. Switch to 2+ columns to create named subsections automatically.</div><div class="items" data-sid="${s.id}" data-col="0">${s.items.map(itemRow).join('')}</div><div class="addrow"><button data-act="add">+ Add a dish</button><button data-act="copy">Copy a dish from another menu…</button></div>`;
  }
  h+=`</div>`;
  h+=`<div class="rootdropzone" data-rootpos="after" data-after="${s.id}"></div>`;
  (m.rootRules||[]).filter(r=>r.afterSectionId===s.id&&r.position!=='top').forEach(r=>{h+=rootRuleRow(r)});
  h+=`<button class="addrootline" data-act="addrootrule" data-after="${s.id}">+ ADD LINE BELOW SECTION</button>`;
 }
 h+=`<div class="rootdropzone edge" data-rootpos="bottom"></div>`;
 (m.rootRules||[]).filter(r=>!r.afterSectionId&&r.position!=='top').forEach(r=>{h+=rootRuleRow(r)});
 h+=`<div class="root-actions"><button class="addsec" id="btnAddSec">+ ADD SECTION</button><button class="addrootline" data-act="addrootrule">+ ADD LINE AT END</button></div><div class="foot-ed"><div class="cap">FOOTER - PRINTED AT THE BOTTOM OF THE PAGE</div><textarea id="edFooter" placeholder="Footer lines…">${esc(m.footer||'')}</textarea><label class="chkline"><input type="checkbox" id="edShowKey" ${m.style.showKey?'checked':''}> Print the dietary key automatically (only the codes used on this menu)</label></div>`;
 sc.innerHTML=h;
}
/* editor events (delegated) */
$('#edScroll').addEventListener('input',e=>{
 const m=cur();
 if(e.target.id==='edFooter'){m.footer=e.target.value;debPreview();return}
 const secEl=e.target.closest('.sec');
 const itEl=e.target.closest('.item');
 if(e.target.dataset.colname!=null&&secEl){const s=m.sections.find(x=>x.id===secEl.dataset.sid);if(s){normaliseSectionColumns(s);s.columnNames[Number(e.target.dataset.colname)]=e.target.value;debPreview()}return}
 const f=e.target.dataset.f;if(!f)return;
 if(itEl){const r=findItem(m,itEl.dataset.iid);if(r){r.it[f]=e.target.value;debPreview()}}
 else if(secEl){const s=m.sections.find(x=>x.id===secEl.dataset.sid);if(s){s[f]=e.target.value;debPreview()}}
});
$('#edScroll').addEventListener('change',e=>{
 if(e.target.id==='edShowKey'){snapshot();cur().style.showKey=e.target.checked;commit()}else{persist()}
});
let prevT;function debPreview(){clearTimeout(prevT);prevT=setTimeout(()=>{persist();renderPreview();renderRail()},160)}
$('#edScroll').addEventListener('click',e=>{
 const m=cur();
 if(e.target.id==='btnAddSec'){snapshot();m.sections.push(sec('New Section',[]));commit({ed:true});return}
 const tagB=e.target.closest('[data-tag]');
 if(tagB){snapshot();const r=findItem(m,tagB.closest('.item').dataset.iid);const c=tagB.dataset.tag;
  const i=(r.it.tags=r.it.tags||[]).findIndex(t=>t.c===c);
  if(i<0)r.it.tags.push(T(c));else if(!r.it.tags[i].r)r.it.tags[i].r=true;else r.it.tags.splice(i,1);
  commit({ed:true});return}
 const b=e.target.closest('[data-act]');if(!b)return;
 const act=b.dataset.act;
 const secEl=b.closest('.sec');const s=secEl?m.sections.find(x=>x.id===secEl.dataset.sid):null;
 const itEl=b.closest('.item');
 snapshot();
 if(act==='add'){const it=item('','','',[]);it.col=Number(b.dataset.col)||0;s.items.push(it);commit({ed:true});
   const rows=$$(`.items[data-sid="${s.id}"] .item`);const last=rows[rows.length-1];if(last){const nm=last.querySelector('.iname');if(nm)nm.focus()}return}
 if(act==='addrootrule'){m.rootRules=m.rootRules||[];m.rootRules.push({id:uid(),rule:true,afterSectionId:b.dataset.after||null,position:b.dataset.after?'between':'bottom'});commit({ed:true});return}
 if(act==='delrootrule'){const rr=b.closest('.rootrule');m.rootRules=(m.rootRules||[]).filter(r=>r.id!==rr.dataset.rid);commit({ed:true});return}
 if(act==='copy'){openDishPicker(s.id);return}
 if(act==='secdel'){if(s.items.length&&!confirm(`Delete section “${s.name}” and its contents?`))return;m.sections=m.sections.filter(x=>x!==s);commit({ed:true});return}
 if(act==='secup'||act==='secdn'){const i=m.sections.indexOf(s);const j=act==='secup'?i-1:i+1;if(j<0||j>=m.sections.length)return;[m.sections[i],m.sections[j]]=[m.sections[j],m.sections[i]];commit({ed:true});return}
 if(act==='secprices'){s.prices=!s.prices;commit({ed:true});return}
 if(act==='secdesc'){s.descMode=s.descMode==='below'?'inline':'below';commit({ed:true});return}
 if(act==='seccols'){s.cols=(Number(s.cols)||1)%4+1;normaliseSectionColumns(s);commit({ed:true});return}
 if(itEl){const r=findItem(m,itEl.dataset.iid);if(!r)return;
  if(act==='hide'&&!r.it.rule){r.it.hidden=!r.it.hidden;commit({ed:true})}
  if(act==='del'){if(!r.it.rule&&r.it.name&&!confirm(`Delete “${r.it.name}”?`))return;r.s.items=r.s.items.filter(x=>x!==r.it);commit({ed:true})}
 }
});

