/* ================= drag & drop (pointer-based, mouse + touch) ================= */
let drag=null;
$('#edScroll').addEventListener('pointerdown',e=>{
 const h=e.target.closest('.handle');if(!h)return;
 const row=h.closest('.item,.rootrule');if(!row)return;
 e.preventDefault();
 const m=cur();
 const isRule=row.classList.contains('rootrule');
 let label='horizontal line';
 if(!isRule){const r=findItem(m,row.dataset.iid);if(!r)return;label=r.it.name||'(untitled dish)'}
 const ghost=document.createElement('div');ghost.className='ghost';ghost.textContent=isRule?'── horizontal line ──':label;
 document.body.appendChild(ghost);
 const line=document.createElement('div');line.className='drop-line';
 drag={kind:isRule?'rule':'dish',iid:row.dataset.iid,rid:row.dataset.rid,row,ghost,line,target:null};
 row.classList.add('dragging');moveGhost(e);
 window.addEventListener('pointermove',onDragMove,{passive:false});
 window.addEventListener('pointerup',onDragEnd,{once:true});
 window.addEventListener('pointercancel',onDragEnd,{once:true});
});
function moveGhost(e){drag.ghost.style.left=(e.clientX+12)+'px';drag.ghost.style.top=(e.clientY-14)+'px'}
function clearDragTargets(){drag.line.remove();drag.target=null;$$('.collane.drop-hot').forEach(x=>x.classList.remove('drop-hot'));$$('.rootdropzone.hot').forEach(x=>x.classList.remove('hot'))}
function onDragMove(e){
 if(!drag)return;e.preventDefault();moveGhost(e);
 const sc=$('#edScroll'),rect=sc.getBoundingClientRect();
 if(e.clientY<rect.top+46)sc.scrollTop-=9;else if(e.clientY>rect.bottom-46)sc.scrollTop+=9;
 drag.ghost.style.display='none';const el=document.elementFromPoint(e.clientX,e.clientY);drag.ghost.style.display='';
 clearDragTargets();
 if(drag.kind==='rule'){
   const z=el&&el.closest('.rootdropzone');
   if(!z)return;z.classList.add('hot');
   drag.target={root:true,pos:z.dataset.rootpos,after:z.dataset.after||null};return;
 }
 const items=el&&el.closest('.items');if(!items)return;
 const lane=items.closest('.collane');if(lane)lane.classList.add('drop-hot');
 const rows=[...items.querySelectorAll('.item')].filter(x=>x!==drag.row);let placed=false;
 for(const rw of rows){const rr=rw.getBoundingClientRect();if(e.clientY<rr.top+rr.height/2){items.insertBefore(drag.line,rw);drag.target={sid:items.dataset.sid,col:Number(items.dataset.col)||0,before:rw.dataset.iid};placed=true;break}}
 if(!placed){items.appendChild(drag.line);drag.target={sid:items.dataset.sid,col:Number(items.dataset.col)||0,before:null}}
}
function onDragEnd(){
 if(!drag)return;window.removeEventListener('pointermove',onDragMove);
 drag.ghost.remove();drag.line.remove();drag.row.classList.remove('dragging');$$('.collane.drop-hot').forEach(x=>x.classList.remove('drop-hot'));$$('.rootdropzone.hot').forEach(x=>x.classList.remove('hot'));
 if(drag.target){const m=cur();snapshot();
   if(drag.kind==='rule'){
     const r=(m.rootRules||[]).find(x=>x.id===drag.rid);
     if(r){if(drag.target.pos==='top'){r.position='top';r.afterSectionId=null}else if(drag.target.pos==='bottom'){r.position='bottom';r.afterSectionId=null}else{r.position='between';r.afterSectionId=drag.target.after||null}}
   }else{
     const from=findItem(m,drag.iid);if(from){from.s.items=from.s.items.filter(x=>x!==from.it);const dest=m.sections.find(s=>s.id===drag.target.sid);from.it.col=dest.cols>1?drag.target.col:0;if(drag.target.before){const bi=dest.items.findIndex(x=>x.id===drag.target.before);dest.items.splice(bi,0,from.it)}else dest.items.push(from.it)}
   }
   commit({ed:true});
 }
 drag=null;
}

/* ================= dish picker ================= */
let pickTarget=null;
function openDishPicker(sid){pickTarget=sid;$('#dishSearch').value='';renderDishPick('');$('#ovDish').classList.add('show');setTimeout(()=>$('#dishSearch').focus(),50)}
function renderDishPick(q){
 q=q.toLowerCase();
 let h='';
 for(const m of state.menus){
  const hits=[];
  m.sections.forEach(s=>s.items.forEach(i=>{if(i.name&&(!q||(i.name+' '+i.desc).toLowerCase().includes(q)))hits.push(i)}));
  if(!hits.length)continue;
  h+=`<div class="dp-g">${esc(m.name.toUpperCase())}</div>`;
  h+=hits.map(i=>`<button class="dp-i" data-m="${m.id}" data-i="${i.id}"><span class="n">${esc(i.name)}</span>${i.price?` <span style="font-size:12px;color:#8A8074">${esc(i.price)}</span>`:''}${i.desc?`<div class="d">${esc(i.desc)}</div>`:''}</button>`).join('');
 }
 $('#dishPick').innerHTML=h||'<div style="padding:16px;color:#9A9082;font-style:italic">No dishes found.</div>';
}
$('#dishSearch').addEventListener('input',e=>renderDishPick(e.target.value));
$('#dishPick').addEventListener('click',e=>{
 const b=e.target.closest('.dp-i');if(!b)return;
 const src=state.menus.find(m=>m.id===b.dataset.m);const r=findItem(src,b.dataset.i);
 snapshot();
 const c=JSON.parse(JSON.stringify(r.it));c.id=uid();c.hidden=false;
 const dest=cur().sections.find(s=>s.id===pickTarget);c.col=0;dest.items.push(c);
 $('#ovDish').classList.remove('show');
 commit({ed:true});
});

/* ================= new-menu template gallery ================= */
function allTemplates(){return[...BUILTINS,...state.templates]}
let selTpl=BUILTINS[0].id;
let pendingDesktopNewDocument=false;
const TEMPLATE_META={
 b1:['Core Layouts','Four-section A4 structure for seasonal restaurant menus.'],
 b2:['Core Layouts','Compact A5 set menu with stacked dish descriptions.'],
 b3:['Core Layouts','A4 menu led by the Griffin crest.'],
 b4:['Events','Full-lockup sharing format for feasts and private dining.'],
 b5:['Events','A5 per-head event or canape structure.'],
 b6:['Core Layouts','A5 set menu with a leading rule for a formal layout.'],
 b7:['Griffin Classics','Two-column A4 roast layout for Sunday service.'],
 g1:['Griffin Classics','A5 set lunch format tuned for Griffin service.'],
 g2:['Griffin Classics','A5 buffet layout with crest header and no dietary key.'],
 g3:['Griffin Classics','A5 canape layout with Griffin pricing note.'],
 g4:['Griffin Classics','A5 dinner set menu with below-line descriptions.'],
 g5:['Griffin Classics','A4 sharing menu with the full Griffin lockup.'],
 g6:['Griffin Classics','A5 private dining structure with clean course sections.'],
 g7:['Griffin Classics','A4 Sunday menu with a two-column main course section.'],
 g8:['Griffin Classics','A5 children menu with crest-led presentation.']
};
const TEMPLATE_ORDER=['Griffin Classics','Core Layouts','Events','User Templates'];
function templateSummary(t){
 const cols=Math.max(1,...(t.sections||[]).map(s=>Number(s.cols)||1));
 const meta=TEMPLATE_META[t.id]||[];
 return{category:t.builtin?(meta[0]||'Core Layouts'):'User Templates',description:t.description||meta[1]||'Saved menu layout.',paper:(t.style&&t.style.paper)||'A4',cols,protected:!!t.builtin};
}
function groupedTemplates(){
 const groups=new Map();
 allTemplates().forEach(t=>{const s=templateSummary(t);if(!groups.has(s.category))groups.set(s.category,[]);groups.get(s.category).push({t,s})});
 return[...groups.entries()].sort((a,b)=>{
  const ai=TEMPLATE_ORDER.indexOf(a[0]),bi=TEMPLATE_ORDER.indexOf(b[0]);
  return(ai<0?99:ai)-(bi<0?99:bi)||a[0].localeCompare(b[0]);
 });
}
function emptyDocumentState(templates){
 const fresh=seedState();
 fresh.menus=[];
 fresh.cur=null;
 fresh.templates=JSON.parse(JSON.stringify(templates||[]));
 return fresh;
}
function tplToSample(t){
 const dishes=[
  {name:'Heritage Tomato',desc:'basil, aged balsamic',price:'9',tags:[T('ve'),T('gf')]},
  {name:'Chicken Parfait',desc:'toasted brioche, chutney',price:'10',tags:[T('gf',1)]},
  {name:'Roast Cod',desc:'brown shrimp butter, greens',price:'24',tags:[T('gf')]},
  {name:'Rump of Lamb',desc:'dauphinoise, red wine jus',price:'28',tags:[T('gf')]},
  {name:'Sticky Toffee',desc:'caramel, pecans',price:'9',tags:[T('v'),T('n')]},
  {name:'Lemon Tart',desc:'crème fraiche',price:'9',tags:[T('v')]}];
 const m={name:'Lunch Menu',date:'',headerNote:t.headerNote||'',footer:t.footer||'',
   style:JSON.parse(JSON.stringify(t.style)),sections:[]};
 m.style.showKey=t.style.showKey!==false;
 t.sections.forEach((ts,i)=>{
  const n=ts.cols===2?4:2;
  const items=[];
  if((i===0&&t.leadRule)||ts.ruleBefore)items.push(rule());
  for(let k=0;k<n;k++){const d=dishes[(i*2+k)%dishes.length];items.push(item(d.name,d.desc,d.price,d.tags))}
  m.sections.push(sec(ts.name,items,{prices:ts.prices!==false,cols:ts.cols||1,note:ts.note||'',descMode:ts.descMode||((t.style||{}).stacked?'below':'inline')}));
 });
 return m;
}
function renderTplGrid(){
 const grid=$('#tplGrid');
 grid.innerHTML=allTemplates().map(t=>{
  const m=tplToSample(t);
  const w=t.style.paper==='A5'?148:210,hh=t.style.paper==='A5'?210:297;
  const scale=Math.min(150/(w*3.7795),182/(hh*3.7795));
  return`<div class="tpl-card ${t.id===selTpl?'sel':''}" data-id="${t.id}">
   ${t.builtin?'':`<button class="del" data-del="${t.id}" title="Delete this template">${ICONS.x}</button>`}
   <div class="thumbbox"><div class="thumb" style="transform:scale(${scale});transform-origin:center">${menuHTML(m,{})}</div></div>
   <div class="nm">${esc(t.name.toUpperCase())}</div>
   <div class="meta">${t.style.paper||'A4'}${t.builtin?'':' · YOURS'}</div>
  </div>`}).join('');
}
function templateCardHtml(t,s){
 const m=tplToSample(t);
 const w=t.style.paper==='A5'?148:210,hh=t.style.paper==='A5'?210:297;
 const scale=Math.min(150/(w*3.7795),182/(hh*3.7795));
 return`<div class="tpl-card ${t.id===selTpl?'sel':''}" data-id="${t.id}">
  ${t.builtin?'':`<button class="del" data-del="${t.id}" title="Delete this template">${ICONS.x}</button>`}
  <div class="thumbbox"><div class="thumb" style="transform:scale(${scale});transform-origin:center">${menuHTML(m,{})}</div></div>
  <div class="nm">${esc(t.name.toUpperCase())}</div>
  <div class="tpl-desc">${esc(s.description)}</div>
  <div class="meta"><span>${esc(s.paper)}</span><span>${s.cols} column${s.cols===1?'':'s'}</span>${t.builtin?'':'<span>Yours</span>'}</div>
  <button class="tpl-use" data-use="${t.id}">Use Template</button>
 </div>`;
}
renderTplGrid=function(){
 const grid=$('#tplGrid');
 grid.innerHTML=groupedTemplates().map(([category,items])=>`<section class="tpl-group">
  <h3>${esc(category)}</h3>
  <div class="tpl-group-grid">${items.map(({t,s})=>templateCardHtml(t,s)).join('')}</div>
 </section>`).join('');
};
function openGallery(){selTpl=BUILTINS[0].id;$('#newMenuName').value='';renderTplGrid();$('#ovTpl').classList.add('show')}
$('#tplGrid').addEventListener('click',e=>{
 const del=e.target.closest('[data-del]');
 if(del){if(confirm('Delete this template? Menus made from it are unaffected.')){snapshot();state.templates=state.templates.filter(t=>t.id!==del.dataset.del);persist();renderTplGrid()}return}
 const use=e.target.closest('[data-use]');
 if(use){selTpl=use.dataset.use;$('#btnCreateMenu').click();return}
 const card=e.target.closest('.tpl-card');if(!card)return;
 selTpl=card.dataset.id;renderTplGrid();
});
async function createMenuFromTemplate(templateId, options){
 const t=allTemplates().find(x=>x.id===templateId);if(!t)return false;
 options=options||{};
 const name=options.name||$('#newMenuName')?.value.trim()||'New Menu';
 const customTemplates=state.templates||[];
 if(options.newDocument&&window.griffinDesktop){
  await window.griffinDesktop.newDocument();
  suppressDirty=true;state=emptyDocumentState(customTemplates);suppressDirty=false;
 }else snapshot();
 const m={id:uid(),name,date:todayISO(),style:JSON.parse(JSON.stringify(t.style)),headerNote:t.headerNote||'',footer:t.footer||'',
  sections:t.sections.map((s,i)=>sec(s.name,((i===0&&t.leadRule)||s.ruleBefore)?[rule()]:[],{prices:s.prices!==false,cols:s.cols||1,note:s.note||'',descMode:s.descMode||((t.style||{}).stacked?'below':'inline')}))};
 state.menus.unshift(m);state.cur=m.id;followFit=true;
 $('#ovTpl')?.classList.remove('show');
 if(options.newDocument){pendingDesktopNewDocument=false;desktopFilePath=null}
 commit({ed:true});
 if(innerWidth<=940)setTab('edit');
 return true;
}
$('#btnCreateMenu').addEventListener('click',async()=>{
 await createMenuFromTemplate(selTpl,{newDocument:pendingDesktopNewDocument});
});

