/* ================= release hardening layer ================= */
const RELEASE_DEFAULTS={sectionGap:100,dishGap:100,innerRule:34,edgeRule:94,footerGap:100,colDivider:86};
function releaseSettings(){
 state.settings.layout=Object.assign({},RELEASE_DEFAULTS,state.settings.layout||{});
 return state.settings.layout;
}
function applyReleaseSettings(){
 const x=releaseSettings(),root=document.documentElement.style;
 root.setProperty('--section-gap-scale',x.sectionGap/100);
 root.setProperty('--dish-gap-scale',x.dishGap/100);
 root.setProperty('--inner-rule-width',x.innerRule+'%');
 root.setProperty('--edge-rule-width',x.edgeRule+'%');
 root.setProperty('--footer-gap-scale',x.footerGap/100);
 root.setProperty('--col-divider-length',x.colDivider+'%');
}
function bindReleaseSettings(){
 const defs=[
  ['setSectionGap','outSectionGap','sectionGap',v=>v+'%'],
  ['setDishGap','outDishGap','dishGap',v=>v+'%'],
  ['setInnerRule','outInnerRule','innerRule',v=>v+'%'],
  ['setEdgeRule','outEdgeRule','edgeRule',v=>v+'%'],
  ['setFooterGap','outFooterGap','footerGap',v=>v+'%'],
  ['setColDivider','outColDivider','colDivider',v=>v+'%']
 ];
 const refresh=()=>{const x=releaseSettings();defs.forEach(([iid,oid,key,fmt])=>{const i=$('#'+iid),o=$('#'+oid);if(i)i.value=x[key];if(o)o.textContent=fmt(x[key])})};
 defs.forEach(([iid,oid,key,fmt])=>{const i=$('#'+iid),o=$('#'+oid);if(!i)return;i.addEventListener('input',()=>{const x=releaseSettings();x[key]=Number(i.value);if(o)o.textContent=fmt(x[key]);applyReleaseSettings();renderPreview(false)});i.addEventListener('change',persist)});
 const reset=$('#btnResetLayoutSettings');if(reset)reset.addEventListener('click',()=>{state.settings.layout=Object.assign({},RELEASE_DEFAULTS);applyReleaseSettings();refresh();persist();renderPreview(false)});
 const original=$('#btnSettings');if(original)original.addEventListener('click',()=>requestAnimationFrame(refresh));
 refresh();
}

/* Fixed-paper measurement - independent of visual zoom and browser zoom. */
function productionInfo(root){
 root=root||$('#pagewrap');
 const page=root&&root.querySelector('.page'),inner=root&&root.querySelector('.inner'),body=root&&root.querySelector('.body'),foot=root&&root.querySelector('.print-footer-zone');
 if(!page||!inner||!body||!foot)return{over:false,footerCollision:false,pages:1,used:0,limit:0,spare:0};
 const ir=inner.getBoundingClientRect(),br=body.getBoundingClientRect(),fr=foot.getBoundingClientRect();
 const cs=getComputedStyle(inner),padBottom=parseFloat(cs.paddingBottom)||0;
 const contentBottom=Math.max(br.bottom, ...[...body.querySelectorAll('.mblk')].map(x=>x.getBoundingClientRect().bottom));
 const footerTop=fr.top;
 const physicalBottom=ir.bottom-padBottom;
 const footerCollision=contentBottom>footerTop+0.5;
 const over=fr.bottom>physicalBottom+0.5 || contentBottom>physicalBottom+0.5 || inner.scrollHeight>inner.clientHeight+1;
 const used=Math.max(fr.bottom-ir.top,contentBottom-ir.top);
 const limit=physicalBottom-ir.top;
 return{over,footerCollision,pages:over?Math.max(2,Math.ceil(used/Math.max(1,limit))):1,used,limit,spare:limit-used};
}

/* Replace legacy overflow estimator - no false warning from page min-height growth. */
overflowInfo=function(){return productionInfo($('#pagewrap'))};
checkOverflow=function(){
 const info=productionInfo($('#pagewrap')),chip=$('#warnChip'),wt=$('#warnText');
 chip.classList.toggle('show',info.over||info.footerCollision);
 chip.classList.toggle('warn-footer',info.footerCollision);
 chip.classList.toggle('warn-overflow',info.over&&!info.footerCollision);
 if(wt){
   if(info.footerCollision)wt.textContent='Text reaches the footer';
   else if(info.over)wt.textContent='Does not fit on one page';
   else wt.textContent='Fits on one page';
 }
 return info.over||info.footerCollision;
};
let overflowTimer=0;
scheduleOverflowCheck=function(){clearTimeout(overflowTimer);requestAnimationFrame(()=>requestAnimationFrame(checkOverflow));overflowTimer=setTimeout(checkOverflow,180)};

/* Pure zoom: measure the untransformed paper box once and only scale the wrapper. */
applyZoom=function(){
 const wrap=$('#pagewrap'),page=wrap&&wrap.querySelector('.page');if(!page)return;
 zoom=Math.max(.2,Math.min(3,zoom));
 const pw=page.offsetWidth,ph=page.offsetHeight;
 wrap.style.transform='scale('+zoom+')';
 wrap.style.width=(pw*zoom)+'px';wrap.style.height=(ph*zoom)+'px';
 const z=$('#scReset');if(z)z.textContent=Math.round(zoom*100)+'%';
};
fitPage=function(){
 const wrap=$('#pagewrap'),page=wrap&&wrap.querySelector('.page'),sc=$('#stageScroll');if(!page||!sc)return;
 const availW=Math.max(1,sc.clientWidth-40),pw=page.offsetWidth;if(pw<10)return;
 baseZoom=Math.min(availW/pw,1.6);if(followFit)zoom=baseZoom;applyZoom();
};

/* Gentle one-page fitting: spacing first, typography only as a last resort. */
function autoFitOnePage(){
 const m=cur();if(!m)return false;snapshot();
 const st=m.style||(m.style={});st.sc=Number(st.sc)||1;st.dn=Number(st.dn)||1;
 const wrap=$('#pagewrap');
 const test=()=>{wrap.innerHTML=menuHTML(m,{edit:true});return productionInfo(wrap)};
 let info=test(),guard=0;
 while((info.over||info.footerCollision)&&guard++<80){
   if(st.dn>0.78)st.dn=+(st.dn-.02).toFixed(2);
   else if(st.sc>0.86)st.sc=+(st.sc-.01).toFixed(2);
   else break;
   info=test();
 }
 commit({ed:true});
 return !(info.over||info.footerCollision);
}
(function replaceAutoFitButton(){
 const old=$('#btnAutoFit');if(!old)return;
 const b=old.cloneNode(true);old.replaceWith(b);
 b.addEventListener('click',()=>{const ok=autoFitOnePage();if(!ok)alert('This menu still needs a little editing to print cleanly on one page. Shorten a description, reduce a section, or move content to another menu.')});
})();

/* Preflight the exact export DOM before opening print. */
async function prepareExactExport(){
 const m=cur(),pr=$('#printRoot');
 if(document.fonts&&document.fonts.ready)await document.fonts.ready;
 pr.innerHTML=menuHTML(m,{edit:false});
 applyReleaseSettings();
 await new Promise(r=>requestAnimationFrame(()=>requestAnimationFrame(r)));
 const info=productionInfo(pr);
 if(info.footerCollision){alert('Export stopped: text would overlap the footer. Use “Shrink to fit” or shorten the menu first.');pr.innerHTML='';return false}
 if(info.over){alert('Export stopped: this menu does not fit safely on one page. Use “Shrink to fit” or shorten the menu first.');pr.innerHTML='';return false}
 let ps=$('#printPage');if(!ps){ps=document.createElement('style');ps.id='printPage';document.head.appendChild(ps)}
 ps.textContent='@page{size:'+(m.style.paper==='A5'?'148mm 210mm':'210mm 297mm')+';margin:0}';
 return true;
}
async function runDesktopExport(kind){
 const desk=window.griffinDesktop;
 if(!desk)return false;
 const b=$('#btnExport'),label=b&&b.innerHTML;
 if(b)b.disabled=true;
 try{
   if(b)b.textContent='Checking...';
   if(!await prepareExactExport())return false;
   const m=cur(),base=(m.name+' '+fmtDate(m.date)).trim()||'Griffin Menu';
   if(kind==='print'){
     if(b)b.textContent='Printing...';
     await desk.printDocument();
   }else if(kind==='png'){
     if(b)b.textContent='Exporting PNG...';
     document.body.classList.add('png-exporting');
     await new Promise(r=>requestAnimationFrame(()=>requestAnimationFrame(r)));
     const page=$('#printRoot .page').getBoundingClientRect();
     await desk.exportPng({defaultName:base+'.png',rect:{x:Math.floor(page.left),y:Math.floor(page.top),width:Math.ceil(page.width),height:Math.ceil(page.height)}});
   }else{
     if(b)b.textContent='Exporting PDF...';
     await desk.exportPdf({paper:m.style.paper==='A5'?'A5':'A4',defaultName:base+'.pdf'});
   }
   return true;
 }finally{
   document.body.classList.remove('png-exporting');
   $('#printRoot').innerHTML='';
   if(b){b.disabled=false;b.innerHTML=label||'Export PDF'}
 }
}
(function installExactExport(){
 const old=$('#btnExport');if(!old)return;
 const b=old.cloneNode(true);old.replaceWith(b);
 b.addEventListener('click',async()=>{
   if(window.griffinDesktop){await runDesktopExport('pdf');return;}
   b.disabled=true;const label=b.innerHTML;
   try{
     b.textContent='Checking...';if(!await prepareExactExport())return;
     const m=cur(),title=document.title;document.title=(m.name+' '+fmtDate(m.date)).trim();
     b.innerHTML=label;window.print();setTimeout(()=>{document.title=title},500);
   }finally{b.disabled=false;b.innerHTML=label}
 });
})();

/* Keep status accurate after live edits without repeated heavy timers. */
const releaseObserver=new ResizeObserver(()=>scheduleOverflowCheck());
function observeReleasePage(){releaseObserver.disconnect();const p=$('#pagewrap .page');if(p)releaseObserver.observe(p)}
const _renderPreview=renderPreview;
renderPreview=function(resetZoom){_renderPreview(resetZoom);applyReleaseSettings();observeReleasePage();scheduleOverflowCheck()};

applyReleaseSettings();
bindReleaseSettings();

/* ================= mobile tabs ================= */
function setTab(t){$('#app').dataset.tab=t;$$('#tabbar button').forEach(b=>b.classList.toggle('on',b.dataset.t===t));if(t==='view'){setTimeout(fitPage,30);setTimeout(fitPage,200)}}
$('#tabbar').addEventListener('click',e=>{const b=e.target.closest('button');if(b)setTab(b.dataset.t)});

/* ================= desktop start menu ================= */
function recentPreviewHtml(entry){
 const docState=entry&&entry.state;
 const m=docState&&(docState.menus||[]).find(x=>x.id===docState.cur)||docState&&docState.menus&&docState.menus[0];
 if(!m)return'<div class="recent-empty">Preview unavailable</div>';
 const paper=(m.style&&m.style.paper)==='A5'?'A5':'A4';
 const w=paper==='A5'?148:210,hh=paper==='A5'?210:297;
 const scale=Math.min(122/(w*3.7795),162/(hh*3.7795));
 return`<div class="recent-thumb"><div class="thumb" style="transform:scale(${scale});transform-origin:center">${menuHTML(m,{})}</div></div>`;
}
function formatRecentDate(ms){
 if(!ms)return'';
 try{return new Intl.DateTimeFormat('en-GB',{day:'2-digit',month:'short',year:'numeric'}).format(new Date(ms))}catch{return''}
}
function renderWelcomeRecent(recent){
 const box=$('#welcomeRecent');if(!box)return;
 const items=(recent||[]).slice(0,6);
 if(!items.length){box.innerHTML='<div class="welcome-empty">No recent menus yet.</div>';return}
 box.innerHTML=items.map((entry,i)=>`<button class="recent-card" data-recent="${i}">
  ${recentPreviewHtml(entry)}
  <span class="recent-name">${esc(entry.name||entry.fileName||'Untitled')}</span>
  <span class="recent-path">${esc(entry.filePath||'')}</span>
  <span class="recent-date">${esc(formatRecentDate(entry.modifiedMs))}</span>
 </button>`).join('');
 box._recentItems=items;
}
function showWelcome(initial){
 const welcome=$('#welcome');if(!welcome)return;
 renderWelcomeRecent(initial&&initial.recent||[]);
 welcome.hidden=false;
 requestAnimationFrame(()=>welcome.classList.add('show'));
}
function hideWelcome(){
 const welcome=$('#welcome');if(!welcome)return;
 welcome.classList.remove('show');
 welcome.hidden=true;
}
$('#welcomeTemplate')?.addEventListener('click',()=>{pendingDesktopNewDocument=true;hideWelcome();closePops();openGallery()});
$('#welcomeOpen')?.addEventListener('click',async()=>{await desktopOpen()});
$('#welcomeRecent')?.addEventListener('click',async(e)=>{
 const card=e.target.closest('[data-recent]');if(!card)return;
 const entry=e.currentTarget._recentItems&&e.currentTarget._recentItems[Number(card.dataset.recent)];
 if(entry&&entry.filePath)await desktopOpenRecent(entry.filePath);
});

/* ================= desktop document bridge ================= */
const isDesktop=!!window.griffinDesktop;
let desktopReady=false,desktopDirty=false,desktopFilePath=null,autosaveTimer=0,suppressDirty=false;
const originalPersist=persist;
persist=function(){originalPersist();if(desktopReady&&!suppressDirty)markDesktopDirty()};
function currentDocumentTitle(){const m=cur();return (desktopDirty?'* ':'')+(desktopFilePath?desktopFilePath.split(/[\\/]/).pop():(m&&m.name?m.name:'Untitled'))}
function updateDesktopTitle(){if(isDesktop)window.griffinDesktop.setTitle(currentDocumentTitle())}
function markDesktopDirty(){desktopDirty=true;window.griffinDesktop.setDirty(true);updateDesktopTitle();scheduleDesktopAutosave()}
function scheduleDesktopAutosave(){clearTimeout(autosaveTimer);autosaveTimer=setTimeout(()=>{if(desktopReady&&desktopDirty)window.griffinDesktop.autosave(state).catch(()=>{})},900)}
function clearDesktopDirty(filePath){desktopDirty=false;if(filePath!==undefined)desktopFilePath=filePath;window.griffinDesktop.setDirty(false);updateDesktopTitle()}
function normaliseLoadedState(nextState){
 state=nextState;if(!state.settings)state.settings=seedState().settings;
 if(!state.settings.dietKey)state.settings.dietKey=seedState().settings.dietKey;
 if(state.settings.railWidth===undefined)state.settings.railWidth=230;
 if(!state.cur||!state.menus.find(m=>m.id===state.cur))state.cur=state.menus[0]&&state.menus[0].id;
 applyRailWidth();applyEditorWidth();applyRailHidden();applyReleaseSettings();renderAll(true);
}
function confirmLoseChanges(){return !desktopDirty||confirm('Discard unsaved changes?')}
async function desktopNew(){if(!confirmLoseChanges())return;await window.griffinDesktop.showStart()}
async function desktopOpen(){if(!confirmLoseChanges())return;const res=await window.griffinDesktop.openDocument();if(res&&res.canceled)return;if(res&&res.document){suppressDirty=true;normaliseLoadedState(res.document.state);suppressDirty=false;clearDesktopDirty(res.filePath)}}
async function desktopOpenRecent(filePath){if(!confirmLoseChanges())return;const res=await window.griffinDesktop.openRecent(filePath);if(res&&res.document){suppressDirty=true;normaliseLoadedState(res.document.state);suppressDirty=false;clearDesktopDirty(res.filePath)}}
async function desktopSave(){const res=await window.griffinDesktop.saveDocument(state);if(res&&!res.canceled)clearDesktopDirty(res.filePath);return res&&!res.canceled}
async function desktopSaveAs(){const res=await window.griffinDesktop.saveDocumentAs(state);if(res&&!res.canceled)clearDesktopDirty(res.filePath);return res&&!res.canceled}
function duplicateCurrentMenu(){const m=cur();if(!m)return;duplicateMenu(m)}
function routeDesktopCommand(payload){
 const c=payload&&payload.command;
 if(c==='new'||c==='new-template')desktopNew();else if(c==='new-menu'){pendingDesktopNewDocument=false;closePops();openGallery()}else if(c==='open')desktopOpen();else if(c==='open-recent')desktopOpenRecent(payload.filePath);
 else if(c==='save')desktopSave();else if(c==='save-as')desktopSaveAs();else if(c==='export-pdf')runDesktopExport('pdf');else if(c==='export-png')runDesktopExport('png');else if(c==='print')runDesktopExport('print');
 else if(c==='undo')undo();else if(c==='redo')alert('Redo is not available for this edit yet.');else if(c==='duplicate')$('#btnDup').click();else if(c==='settings'){$('#ovSettings').classList.add('show');renderSettings()}
 else if(c==='zoom-in')setZoom(zoom*1.18);else if(c==='zoom-out')setZoom(zoom/1.18);else if(c==='actual-size')setZoom(1);else if(c==='fit-page'){followFit=true;fitPage()}
 else if(c==='toggle-full-screen')document.documentElement.requestFullscreen?.();else if(c==='toggle-guides')document.body.classList.toggle('show-guides');else if(c==='toggle-safe-area')document.body.classList.toggle('show-safe-area');
}
async function bootDesktop(){
 window.griffinDesktop.onCommand(routeDesktopCommand);
 window.griffinDesktop.onSaveAndClose(async()=>{if(await desktopSave())window.griffinDesktop.confirmCloseDone()});
 const initial=await window.griffinDesktop.getInitialDocument();desktopFilePath=initial.filePath||null;
 if(initial.document&&initial.document.state){
  suppressDirty=true;normaliseLoadedState(initial.document.state);suppressDirty=false;
 }
 if(initial.autosaveDocument&&confirm('Recovered autosave data is available. Restore it now?')){normaliseLoadedState(initial.autosaveDocument.state);markDesktopDirty();return}
 if(initial.startupAction&&initial.startupAction.type==='template'){
  await createMenuFromTemplate(initial.startupAction.templateId||BUILTINS[0].id,{newDocument:true});
  markDesktopDirty();
  return;
 }
 clearDesktopDirty(desktopFilePath);
}

/* ================= boot ================= */
function renderAll(resetZoom){renderRail();renderEditor();renderPreview(resetZoom)}
load();
if(!state.settings.dietKey)state.settings.dietKey=seedState().settings.dietKey;
if(state.settings.railWidth===undefined)state.settings.railWidth=230;
if(!state.cur||!state.menus.find(m=>m.id===state.cur))state.cur=state.menus[0]&&state.menus[0].id;
applyRailWidth();applyEditorWidth();applyRailHidden();
renderAll();
if(!state.settings.tipSeen){$('#tipbar').style.display='flex'}
$('#tipClose').addEventListener('click',()=>{state.settings.tipSeen=true;persist();$('#tipbar').style.display='none';fitPage()});
if(isDesktop)bootDesktop().then(()=>{desktopReady=true;updateDesktopTitle()});
window.addEventListener('afterprint',()=>{$('#printRoot').innerHTML=''});
